const fs = require("fs");
const path = require("path");

const root = process.cwd();

const LIGHT_LOGO_BASE64 = "";
const DARK_LOGO_BASE64 = "";
const COMPONENT_CODE = "\"use client\";\n\nimport { ImgHTMLAttributes, useEffect, useState } from \"react\";\n\ntype LoadLinkLogoProps = ImgHTMLAttributes<HTMLImageElement> & {\n  containerClassName?: string;\n  showGlow?: boolean;\n};\n\nfunction detectDarkMode() {\n  if (typeof window === \"undefined\") return false;\n\n  const savedTheme = localStorage.getItem(\"loadlink-theme\");\n  if (savedTheme === \"dark\") return true;\n  if (savedTheme === \"light\") return false;\n\n  return Boolean(\n    document.querySelector(\"main.bg-black\") ||\n    document.querySelector(\"header.bg-black\") ||\n    document.querySelector(\".bg-black\") ||\n    document.documentElement.classList.contains(\"dark\") ||\n    document.body.classList.contains(\"dark\")\n  );\n}\n\nexport default function LoadLinkLogo({\n  className = \"\",\n  containerClassName = \"\",\n  showGlow = true,\n  alt = \"LoadLink\",\n  ...props\n}: LoadLinkLogoProps) {\n  const [darkMode, setDarkMode] = useState(false);\n\n  useEffect(() => {\n    const sync = () => setDarkMode(detectDarkMode());\n\n    sync();\n\n    const observer = new MutationObserver(sync);\n    observer.observe(document.documentElement, { attributes: true, childList: true, subtree: true });\n    if (document.body) observer.observe(document.body, { attributes: true, childList: true, subtree: true });\n\n    const timer = window.setInterval(sync, 180);\n\n    window.addEventListener(\"storage\", sync);\n    window.addEventListener(\"click\", sync);\n    window.addEventListener(\"loadlink-theme-change\", sync);\n\n    return () => {\n      observer.disconnect();\n      window.clearInterval(timer);\n      window.removeEventListener(\"storage\", sync);\n      window.removeEventListener(\"click\", sync);\n      window.removeEventListener(\"loadlink-theme-change\", sync);\n    };\n  }, []);\n\n  return (\n    <span className={`loadlink-logo-wrap ${containerClassName}`}>\n      {showGlow ? <span aria-hidden=\"true\" className=\"loadlink-logo-glow\" /> : null}\n\n      <img\n        src={darkMode ? \"/images/loadlink-logo-dark.png?v=smooth-owner-fix\" : \"/images/loadlink-logo-light.png?v=smooth-owner-fix\"}\n        alt={alt}\n        className={`loadlink-logo-img ${className}`}\n        style={{ filter: \"none\" }}\n        {...props}\n      />\n    </span>\n  );\n}\n";
const JOBS_PAGE_CODE = "\"use client\";\n\nimport Link from \"next/link\";\nimport { useEffect, useMemo, useRef, useState } from \"react\";\nimport LoadLinkLogo from \"@/components/LoadLinkLogo\";\nimport LoadLinkLoading from \"@/components/LoadLinkLoading\";\nimport RecentActivityPanel from \"@/components/RecentActivityPanel\";\nimport { isSupabaseConfigured, supabase } from \"@/lib/supabaseClient\";\n\ntype VehicleGroup = \"Catering / Event\" | \"Trucks / Trailers\" | \"Farming / Mining\";\n\ntype JobListing = {\n  id: string;\n  title: string;\n  city: string;\n  group: VehicleGroup;\n  rate: string;\n  postedBy: string;\n  contactNumber: string;\n  description: string;\n  photos: string[];\n  sponsored: boolean;\n  packageType?: \"standard\" | \"pro\";\n  createdAt?: string;\n  viewCount?: number;\n  lastViewedAt?: string | null;\n};\n\ntype JobRow = {\n  id: string;\n  title: string;\n  city: string;\n  vehicle_group: string;\n  rate: string;\n  posted_by: string;\n  contact_number: string | null;\n  description: string;\n  photos: string[] | null;\n  sponsored: boolean | null;\n  package_type: string | null;\n  created_at: string | null;\n  view_count?: number | null;\n  last_viewed_at?: string | null;\n};\n\nconst cityOptions = [\n  \"Johannesburg\", \"Sandton\", \"Midrand\", \"Pretoria\", \"Centurion\", \"Soweto\", \"Tembisa\", \"Kempton Park\",\n  \"Boksburg\", \"Benoni\", \"Germiston\", \"Alberton\", \"Randburg\", \"Roodepoort\", \"Krugersdorp\", \"Vereeniging\",\n  \"Vanderbijlpark\", \"Springs\", \"Brakpan\", \"Nigel\", \"Heidelberg\", \"Meyerton\", \"Carletonville\", \"Westonaria\",\n  \"Bronkhorstspruit\", \"Cullinan\", \"Durban\", \"Pinetown\", \"Umhlanga\", \"Ballito\", \"Pietermaritzburg\",\n  \"Richards Bay\", \"Empangeni\", \"Newcastle\", \"Ladysmith\", \"Dundee\", \"Vryheid\", \"Amanzimtoti\", \"Tongaat\",\n  \"KwaDukuza\", \"Stanger\", \"Port Shepstone\", \"Margate\", \"Chatsworth\", \"Umlazi\", \"Cape Town\", \"Bellville\",\n  \"Stellenbosch\", \"Paarl\", \"Worcester\", \"George\", \"Mossel Bay\", \"Knysna\", \"Hermanus\", \"Somerset West\",\n  \"Atlantis\", \"Malmesbury\", \"Robertson\", \"Langebaan\", \"Saldanha\", \"Vredenburg\", \"Mitchells Plain\",\n  \"Khayelitsha\", \"Caledon\", \"Beaufort West\", \"Port Elizabeth\", \"Gqeberha\", \"East London\", \"Mthatha\",\n  \"Queenstown\", \"Komani\", \"Uitenhage\", \"Kariega\", \"Graaff-Reinet\", \"Butterworth\", \"King William's Town\",\n  \"Qonce\", \"Mount Frere\", \"Bloemfontein\", \"Welkom\", \"Bethlehem\", \"Sasolburg\", \"Parys\", \"Phuthaditjhaba\",\n  \"Kroonstad\", \"Harrismith\", \"Kimberley\", \"Upington\", \"Kuruman\", \"Springbok\", \"De Aar\", \"Rustenburg\",\n  \"Klerksdorp\", \"Potchefstroom\", \"Mahikeng\", \"Brits\", \"Lichtenburg\", \"Polokwane\", \"Tzaneen\",\n  \"Thohoyandou\", \"Lephalale\", \"Louis Trichardt\", \"Mokopane\", \"Phalaborwa\", \"Musina\", \"Nelspruit\",\n  \"Mbombela\", \"Witbank\", \"Emalahleni\", \"Middelburg\", \"Secunda\", \"Ermelo\", \"Standerton\", \"Barberton\",\n  \"Lydenburg\"\n];\n\nconst vehicleGroups: VehicleGroup[] = [\"Catering / Event\", \"Trucks / Trailers\", \"Farming / Mining\"];\n\nconst starterJobs: JobListing[] = [\n  {\n    id: \"demo-1\",\n    title: \"Daily delivery route\",\n    city: \"Johannesburg\",\n    group: \"Trucks / Trailers\",\n    rate: \"From R1 850 / day\",\n    postedBy: \"MoveFast Logistics\",\n    contactNumber: \"010 000 0000\",\n    description: \"Closed truck or bakkie needed for local deliveries. Loading support preferred.\",\n    photos: [\"/images/jobs/job-card-1.jpg\", \"/images/jobs/job-card-2.jpg\", \"/images/jobs/job-card-3.jpg\"],\n    sponsored: true,\n    packageType: \"standard\",\n    createdAt: new Date().toISOString(),\n    viewCount: 0,\n  },\n];\n\nfunction mapJobRow(row: JobRow): JobListing {\n  return {\n    id: row.id,\n    title: row.title,\n    city: row.city,\n    group: row.vehicle_group as VehicleGroup,\n    rate: row.rate,\n    postedBy: row.posted_by,\n    contactNumber: row.contact_number || \"No number added\",\n    description: row.description,\n    photos: row.photos && row.photos.length > 0 ? row.photos : [\"/images/jobs/job-card-1.jpg\"],\n    sponsored: Boolean(row.sponsored),\n    packageType: row.package_type === \"pro\" ? \"pro\" : \"standard\",\n    createdAt: row.created_at || undefined,\n    viewCount: row.view_count || 0,\n    lastViewedAt: row.last_viewed_at || null,\n  };\n}\n\nfunction getDeviceKey() {\n  if (typeof window === \"undefined\") return \"\";\n\n  const existing = localStorage.getItem(\"loadlink-device-key\");\n  if (existing) return existing;\n\n  const key = `${Date.now()}-${Math.random().toString(36).slice(2)}-${crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2)}`;\n  localStorage.setItem(\"loadlink-device-key\", key);\n  return key;\n}\n\nfunction getOwnedJobs(): Record<string, string> {\n  if (typeof window === \"undefined\") return {};\n  try {\n    return JSON.parse(localStorage.getItem(\"loadlink-owned-job-keys\") || \"{}\");\n  } catch {\n    localStorage.removeItem(\"loadlink-owned-job-keys\");\n    return {};\n  }\n}\n\nfunction saveViewedJob(job: JobListing) {\n  try {\n    const saved = localStorage.getItem(\"loadlink-recent-viewed-jobs\");\n    const current = saved ? JSON.parse(saved) : [];\n    const nextItem = {\n      id: job.id,\n      title: job.title,\n      href: \"/jobs\",\n      category: \"Job\",\n      type: job.group,\n      image: job.photos[0] || \"/images/jobs/job-card-1.jpg\",\n      meta: `${job.city} \u2022 ${formatPostedDate(job.createdAt)}`,\n      savedAt: Date.now(),\n    };\n\n    const next = [nextItem, ...(Array.isArray(current) ? current.filter((item) => item?.id !== job.id) : [])].slice(0, 12);\n    localStorage.setItem(\"loadlink-recent-viewed-jobs\", JSON.stringify(next));\n    window.dispatchEvent(new Event(\"loadlink-recent-activity-updated\"));\n  } catch {\n    localStorage.removeItem(\"loadlink-recent-viewed-jobs\");\n  }\n}\n\nfunction formatPostedDate(value?: string) {\n  if (!value) return \"Posted recently\";\n  const date = new Date(value);\n  if (Number.isNaN(date.getTime())) return \"Posted recently\";\n\n  const diffMs = Date.now() - date.getTime();\n  const minutes = Math.max(0, Math.floor(diffMs / 60000));\n  if (minutes < 1) return \"Posted just now\";\n  if (minutes < 60) return `Posted ${minutes} min ago`;\n  const hours = Math.floor(minutes / 60);\n  if (hours < 24) return `Posted ${hours} hour${hours === 1 ? \"\" : \"s\"} ago`;\n  const days = Math.floor(hours / 24);\n  return `Posted ${days} day${days === 1 ? \"\" : \"s\"} ago`;\n}\n\nfunction buildGreeting(job: JobListing) {\n  const savedNumber = typeof window !== \"undefined\" ? localStorage.getItem(\"loadlink-user-contact-number\") || \"\" : \"\";\n  const requesterNumber = savedNumber || (typeof window !== \"undefined\" ? window.prompt(\"Enter your number so it can be included in the message.\") || \"\" : \"\");\n\n  if (requesterNumber) localStorage.setItem(\"loadlink-user-contact-number\", requesterNumber);\n\n  const subject =\n    job.group === \"Trucks / Trailers\"\n      ? \"this truck\"\n      : job.group === \"Catering / Event\"\n        ? \"this event/catering service\"\n        : \"this farming or mining transport service\";\n\n  return `Hey, I\u2019m interested in ${subject} on LoadLink. Please call me on ${requesterNumber || \"my number\"} when you are available.`;\n}\n\nasync function copyGreeting(job: JobListing) {\n  const message = buildGreeting(job);\n\n  try {\n    await navigator.clipboard.writeText(message);\n    alert(\"Greeting copied. You can paste it to the poster.\");\n  } catch {\n    alert(message);\n  }\n}\n\nfunction whatsappLink(job: JobListing) {\n  const clean = job.contactNumber.replace(/[^\\d+]/g, \"\");\n  const message = buildGreeting(job);\n  const phone = clean.startsWith(\"0\") ? `27${clean.slice(1)}` : clean.replace(\"+\", \"\");\n  return `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;\n}\n\nexport default function JobsPortalPage() {\n  const [darkMode, setDarkMode] = useState(false);\n  const [city, setCity] = useState(\"\");\n  const [group, setGroup] = useState<VehicleGroup | \"\">(\"\");\n  const [showCityOptions, setShowCityOptions] = useState(false);\n  const [showAllCities, setShowAllCities] = useState(false);\n  const [hasSearched, setHasSearched] = useState(false);\n  const [sharedJobs, setSharedJobs] = useState<JobListing[]>([]);\n  const [isSearching, setIsSearching] = useState(false);\n  const [loadingJobs, setLoadingJobs] = useState(true);\n  const [notice, setNotice] = useState(\"\");\n  const [galleryJob, setGalleryJob] = useState<JobListing | null>(null);\n  const [ownedJobs, setOwnedJobs] = useState<Record<string, string>>({});\n  const [editJob, setEditJob] = useState<JobListing | null>(null);\n  const cityWrapperRef = useRef<HTMLLabelElement | null>(null);\n\n  async function fetchJobs() {\n    if (!isSupabaseConfigured) {\n      setNotice(\"Shared jobs database is not connected yet. Check your Supabase environment keys.\");\n      setLoadingJobs(false);\n      return;\n    }\n\n    const { data, error } = await supabase\n      .from(\"job_listings\")\n      .select(\"id,title,city,vehicle_group,rate,posted_by,contact_number,description,photos,sponsored,package_type,created_at,view_count,last_viewed_at\")\n      .order(\"created_at\", { ascending: false });\n\n    if (error) {\n      setNotice(error.message);\n      setLoadingJobs(false);\n      return;\n    }\n\n    setSharedJobs((data || []).map((row) => mapJobRow(row as JobRow)));\n    setNotice(\"\");\n    setLoadingJobs(false);\n  }\n\n  useEffect(() => {\n    const savedTheme = localStorage.getItem(\"loadlink-theme\");\n    if (savedTheme === \"dark\") setDarkMode(true);\n    getDeviceKey();\n    setOwnedJobs(getOwnedJobs());\n    fetchJobs();\n\n    if (!isSupabaseConfigured) return;\n\n    const channel = supabase\n      .channel(\"public-job-listings-live\")\n      .on(\"postgres_changes\", { event: \"*\", schema: \"public\", table: \"job_listings\" }, () => fetchJobs())\n      .subscribe();\n\n    return () => {\n      supabase.removeChannel(channel);\n    };\n  }, []);\n\n  useEffect(() => {\n    function closeCityOptions(e: MouseEvent | TouchEvent) {\n      if (!cityWrapperRef.current?.contains(e.target as Node)) setShowCityOptions(false);\n    }\n\n    document.addEventListener(\"mousedown\", closeCityOptions);\n    document.addEventListener(\"touchstart\", closeCityOptions);\n    return () => {\n      document.removeEventListener(\"mousedown\", closeCityOptions);\n      document.removeEventListener(\"touchstart\", closeCityOptions);\n    };\n  }, []);\n\n  function toggleDarkMode() {\n    const nextMode = !darkMode;\n    setDarkMode(nextMode);\n    localStorage.setItem(\"loadlink-theme\", nextMode ? \"dark\" : \"light\");\n    window.dispatchEvent(new Event(\"loadlink-theme-change\"));\n  }\n\n  const cityMatches = useMemo(() => {\n    const sorted = [...cityOptions].sort((a, b) => a.localeCompare(b));\n    if (showAllCities) return sorted;\n    if (!city.trim()) return sorted.slice(0, 12);\n    return sorted.filter((item) => item.toLowerCase().includes(city.toLowerCase())).slice(0, 16);\n  }, [city, showAllCities]);\n\n  const allJobs = useMemo(() => sharedJobs.length > 0 ? [...sharedJobs, ...starterJobs] : starterJobs, [sharedJobs]);\n\n  const matchingJobs = useMemo(() => {\n    return allJobs.filter((job) => {\n      const cityMatch = !city.trim() || job.city.toLowerCase().includes(city.toLowerCase());\n      const groupMatch = !group || job.group === group;\n      return cityMatch && groupMatch;\n    });\n  }, [allJobs, city, group]);\n\n  function searchJobs() {\n    setIsSearching(true);\n    setHasSearched(true);\n    requestAnimationFrame(() => {\n      document.getElementById(\"matching-jobs\")?.scrollIntoView({ behavior: \"smooth\" });\n      setTimeout(() => setIsSearching(false), 900);\n    });\n  }\n\n  async function openGallery(job: JobListing) {\n    saveViewedJob(job);\n    setGalleryJob(job);\n\n    if (!isSupabaseConfigured || job.id.startsWith(\"demo-\")) return;\n\n    const viewerKey = getDeviceKey();\n    const ownerKey = ownedJobs[job.id];\n\n    if (ownerKey && ownerKey === viewerKey) return;\n\n    await supabase.rpc(\"increment_job_view\", {\n      p_job_id: job.id,\n      p_viewer_key: viewerKey,\n    });\n\n    fetchJobs();\n  }\n\n  async function deleteJob(job: JobListing) {\n    const ownerKey = ownedJobs[job.id];\n    if (!ownerKey) {\n      alert(\"Only the device that posted this job can delete it.\");\n      return;\n    }\n\n    const confirmed = confirm(\"Delete this post from LoadLink?\");\n    if (!confirmed) return;\n\n    const { data, error } = await supabase.rpc(\"delete_job_listing\", {\n      p_job_id: job.id,\n      p_owner_key: ownerKey,\n    });\n\n    if (error || data !== true) {\n      alert(\"This post can only be deleted from the device that created it.\");\n      return;\n    }\n\n    const next = { ...ownedJobs };\n    delete next[job.id];\n    localStorage.setItem(\"loadlink-owned-job-keys\", JSON.stringify(next));\n    setOwnedJobs(next);\n    fetchJobs();\n  }\n\n  return (\n    <main className={`min-h-screen scroll-smooth transition-colors duration-500 ${darkMode ? \"bg-black text-white\" : \"bg-[#fff7df] text-black\"}`}>\n      {isSearching || loadingJobs ? <LoadLinkLoading /> : null}\n      <Header darkMode={darkMode} toggleDarkMode={toggleDarkMode} />\n\n      <section className=\"relative min-h-[82vh] overflow-hidden border-b border-[#f6b800]/40\">\n        <img src=\"/images/jobs/hero.jpg\" alt=\"Truck hire and logistics jobs\" className=\"absolute inset-0 h-full w-full object-cover\" />\n        <div className={`absolute inset-0 ${darkMode ? \"bg-gradient-to-b from-black/15 via-black/32 to-black\" : \"bg-gradient-to-b from-black/5 via-black/20 to-[#fff7df]\"}`} />\n\n        <div className=\"relative mx-auto flex min-h-[82vh] max-w-5xl flex-col justify-end px-5 pb-8 pt-20\">\n          <div className=\"max-w-4xl text-white drop-shadow-[0_4px_16px_rgba(0,0,0,0.95)]\">\n            <p className=\"mb-4 inline-flex border border-[#f6b800] bg-black/35 px-4 py-2 text-xs font-black uppercase tracking-[0.24em] text-[#f6b800]\">\n              Find jobs portal\n            </p>\n\n            <h1 className=\"text-5xl font-black leading-[0.92] tracking-[-0.06em] md:text-7xl\">\n              Find paid logistics work\n            </h1>\n\n            <p className=\"mt-5 max-w-2xl text-base font-bold leading-7 md:text-lg\">\n              For truck owners, drivers, mobile kitchens, mobile fridges, farming vehicles and mining transport operators looking for real posted jobs.\n            </p>\n          </div>\n\n          <div className=\"mt-6 border border-[#f6b800] bg-black/78 p-4 shadow-[0_20px_60px_rgba(0,0,0,0.45)] backdrop-blur-sm md:p-5\">\n            <div className=\"grid gap-3 md:grid-cols-[1fr_1fr_auto]\">\n              <label ref={cityWrapperRef} className=\"relative block\">\n                <span className=\"mb-2 block text-xs font-black uppercase tracking-[0.18em] text-[#f6b800]\">City</span>\n                <input\n                  value={city}\n                  onFocus={() => setShowCityOptions(true)}\n                  onChange={(e) => {\n                    setCity(e.target.value);\n                    setShowCityOptions(true);\n                    setShowAllCities(false);\n                  }}\n                  placeholder=\"Enter city\"\n                  className=\"h-12 w-full border border-white/15 bg-white px-4 text-sm font-semibold text-black outline-none placeholder:text-neutral-500 focus:border-[#f6b800]\"\n                />\n\n                {showCityOptions ? (\n                  <div className=\"absolute z-30 mt-1 max-h-72 w-full overflow-y-auto border border-[#f6b800]/50 bg-white text-black shadow-2xl\">\n                    <button type=\"button\" onClick={() => setShowAllCities((value) => !value)} className=\"block w-full border-b border-black/10 bg-[#fff2bf] px-4 py-3 text-left text-xs font-black uppercase tracking-[0.14em] text-black\">\n                      {showAllCities ? \"Show matching cities\" : \"Show all cities\"}\n                    </button>\n\n                    {cityMatches.map((item) => (\n                      <button key={item} type=\"button\" onClick={() => { setCity(item); setShowCityOptions(false); }} className=\"block w-full border-b border-black/5 px-4 py-3 text-left text-sm font-bold hover:bg-[#fff2bf]\">\n                        {item}\n                      </button>\n                    ))}\n                  </div>\n                ) : null}\n              </label>\n\n              <label className=\"block\">\n                <span className=\"mb-2 block text-xs font-black uppercase tracking-[0.18em] text-[#f6b800]\">Vehicle group</span>\n                <select value={group} onChange={(e) => setGroup(e.target.value as VehicleGroup | \"\")} className=\"h-12 w-full border border-white/15 bg-white px-4 text-sm font-semibold text-black outline-none focus:border-[#f6b800]\">\n                  <option value=\"\">All groups</option>\n                  {vehicleGroups.map((item) => <option key={item} value={item}>{item}</option>)}\n                </select>\n              </label>\n\n              <button onClick={searchJobs} className=\"mt-6 h-12 border border-[#f6b800] bg-[#f6b800] px-8 text-sm font-black uppercase tracking-wide text-black active:scale-[0.99] md:mt-auto\">\n                Search jobs\n              </button>\n            </div>\n          </div>\n\n          <div className=\"mt-4\">\n            <Link href=\"/jobs/list\" className=\"inline-flex items-center gap-2 border border-[#f6b800] bg-[#f6b800] px-5 py-3 text-xs font-black uppercase tracking-wide text-black\">\n              <span className=\"text-lg leading-none\">+</span> List a job\n            </Link>\n          </div>\n        </div>\n      </section>\n\n      <section className=\"mx-auto max-w-5xl px-5 py-10\">\n        <div className={`border p-5 md:p-7 ${darkMode ? \"border-white/10 bg-[#090909]\" : \"border-black/10 bg-white\"}`}>\n          <p className=\"mb-3 text-xs font-black uppercase tracking-[0.26em] text-[#b88900]\">Who this page is for</p>\n          <h2 className=\"text-3xl font-black tracking-[-0.04em] md:text-4xl\">Built for logistics owners looking for work.</h2>\n          <p className={`mt-4 max-w-3xl text-sm leading-7 md:text-base ${darkMode ? \"text-white/70\" : \"text-black/65\"}`}>\n            This page connects operators with jobs that match their city and service category. It is made for truck owners, truck drivers, mobile kitchens, mobile fridges, farming vehicles and mining transport providers who want customers to find them faster.\n          </p>\n\n          {notice ? <p className=\"mt-5 border border-[#f6b800]/60 bg-black px-4 py-3 text-sm font-bold text-[#f6b800]\">{notice}</p> : null}\n        </div>\n      </section>\n\n      <section id=\"matching-jobs\" className=\"mx-auto max-w-5xl px-5 pb-12 pt-4\">\n        <div className=\"mb-6 flex items-end justify-between gap-4\">\n          <div>\n            <p className=\"text-xs font-black uppercase tracking-[0.26em] text-[#b88900]\">Available results</p>\n            <h2 className=\"mt-2 text-4xl font-black tracking-[-0.05em]\">{hasSearched ? \"Matching available jobs\" : \"Available jobs\"}</h2>\n          </div>\n\n          <Link href=\"/jobs/list\" className={`hidden border px-5 py-3 text-xs font-black uppercase tracking-wide md:inline-flex ${darkMode ? \"border-[#f6b800] text-[#f6b800]\" : \"border-black text-black\"}`}>\n            + List a job\n          </Link>\n        </div>\n\n        <div className=\"grid gap-5\">\n          {matchingJobs.length > 0 ? (\n            matchingJobs.map((job) => (\n              <JobCard\n                key={job.id}\n                job={job}\n                darkMode={darkMode}\n                isOwner={Boolean(ownedJobs[job.id])}\n                onOpenGallery={() => openGallery(job)}\n                onDelete={() => deleteJob(job)}\n                onEdit={() => setEditJob(job)}\n              />\n            ))\n          ) : (\n            <div className={`border p-8 text-center ${darkMode ? \"border-white/10 bg-[#0b0b0b] text-white/70\" : \"border-black/10 bg-white text-black/65\"}`}>\n              No jobs match your search yet.\n            </div>\n          )}\n        </div>\n      </section>\n\n      <RecentActivityPanel darkMode={darkMode} />\n      <Footer darkMode={darkMode} />\n\n      {galleryJob ? <PhotoGalleryModal job={galleryJob} onClose={() => setGalleryJob(null)} /> : null}\n      {editJob ? <EditJobModal job={editJob} ownerKey={ownedJobs[editJob.id]} onClose={() => setEditJob(null)} onUpdated={() => { setEditJob(null); fetchJobs(); }} /> : null}\n    </main>\n  );\n}\n\nfunction JobCard({ job, darkMode, isOwner, onOpenGallery, onDelete, onEdit }: { job: JobListing; darkMode: boolean; isOwner: boolean; onOpenGallery: () => void; onDelete: () => void; onEdit: () => void }) {\n  const coverPhoto = job.photos[0] || \"/images/jobs/job-card-1.jpg\";\n  const photoCount = job.photos.length;\n\n  return (\n    <article className={`overflow-hidden border ${darkMode ? \"border-white/10 bg-[#0b0b0b]\" : \"border-black/10 bg-white\"}`}>\n      <button type=\"button\" onClick={onOpenGallery} className=\"group relative block w-full overflow-hidden bg-black text-left\">\n        <div className=\"aspect-[4/3] w-full overflow-hidden md:aspect-[16/9]\">\n          <img src={coverPhoto} alt={job.title} className=\"h-full w-full object-cover transition duration-500 group-active:scale-[1.01] md:group-hover:scale-[1.02]\" />\n        </div>\n\n        <div className=\"absolute inset-0 bg-gradient-to-b from-black/15 via-transparent to-black/70\" />\n        <div className=\"absolute right-3 top-3 bg-black/80 px-3 py-2 text-xs font-black text-white\">{photoCount} photo{photoCount === 1 ? \"\" : \"s\"}</div>\n        <div className=\"absolute bottom-3 left-3 bg-black/85 px-3 py-2 text-[11px] font-black uppercase tracking-[0.14em] text-[#f6b800]\">Tap to view photos</div>\n        {job.sponsored ? <div className=\"absolute left-3 top-3 bg-[#f6b800] px-3 py-2 text-[11px] font-black uppercase tracking-[0.16em] text-black\">Sponsored</div> : null}\n      </button>\n\n      <div className=\"p-5\">\n        <div className=\"flex flex-wrap items-start justify-between gap-4\">\n          <div>\n            <p className=\"mb-2 text-xs font-black uppercase tracking-[0.16em] text-[#b88900]\">{formatPostedDate(job.createdAt)}</p>\n            <h3 className=\"text-2xl font-black tracking-[-0.04em]\">{job.title}</h3>\n            <p className={`mt-2 text-sm ${darkMode ? \"text-white/60\" : \"text-black/60\"}`}>Posted by {job.postedBy}</p>\n          </div>\n          <p className=\"text-right text-lg font-black text-[#b88900]\">{job.rate}</p>\n        </div>\n\n        <div className=\"mt-5 flex flex-wrap gap-2 text-xs font-black\">\n          <span className=\"bg-[#eef2ff] px-3 py-2 text-black\">{job.city}</span>\n          <span className=\"bg-[#eef2ff] px-3 py-2 text-black\">{job.group}</span>\n          <span className=\"bg-[#eef2ff] px-3 py-2 text-black\">{job.packageType === \"pro\" ? \"Pro listing\" : \"Standard listing\"}</span>\n          <span className=\"bg-[#fff2bf] px-3 py-2 text-black\">Contact: {job.contactNumber}</span>\n          <span className=\"bg-black px-3 py-2 text-white\">{job.viewCount || 0} views</span>\n        </div>\n\n        {isOwner && (job.viewCount || 0) > 0 ? (\n          <p className=\"mt-4 border border-[#f6b800]/70 bg-[#f6b800]/10 px-3 py-2 text-xs font-black uppercase tracking-[0.12em] text-[#b88900]\">\n            Notification: someone viewed your post.\n          </p>\n        ) : null}\n\n        <p className={`mt-4 text-sm leading-6 ${darkMode ? \"text-white/70\" : \"text-black/65\"}`}>{job.description}</p>\n\n        <div className=\"mt-5 grid grid-cols-2 gap-3\">\n          <a href={`tel:${job.contactNumber.replace(/\\s/g, \"\")}`} className=\"border border-[#f6b800] bg-[#f6b800] px-4 py-3 text-center text-xs font-black uppercase tracking-wide text-black\">Call poster</a>\n          <a href={whatsappLink(job)} target=\"_blank\" rel=\"noreferrer\" className={`border px-4 py-3 text-center text-xs font-black uppercase tracking-wide ${darkMode ? \"border-white/15 text-white\" : \"border-black/10 text-black\"}`}>Greet poster</a>\n          <button onClick={() => copyGreeting(job)} className={`border px-4 py-3 text-xs font-black uppercase tracking-wide ${darkMode ? \"border-white/15 text-white\" : \"border-black/10 text-black\"}`}>Copy greeting</button>\n          <button className={`border px-4 py-3 text-xs font-black uppercase tracking-wide ${darkMode ? \"border-white/15 text-white\" : \"border-black/10 text-black\"}`}>Save job</button>\n        </div>\n\n        {isOwner ? (\n          <div className=\"mt-3 grid grid-cols-2 gap-3\">\n            <button onClick={onEdit} className=\"border border-[#f6b800] px-4 py-3 text-xs font-black uppercase tracking-wide text-[#b88900]\">Edit post</button>\n            <button onClick={onDelete} className=\"border border-red-500/70 px-4 py-3 text-xs font-black uppercase tracking-wide text-red-500\">Delete post</button>\n          </div>\n        ) : null}\n      </div>\n    </article>\n  );\n}\n\nfunction PhotoGalleryModal({ job, onClose }: { job: JobListing; onClose: () => void }) {\n  return (\n    <div className=\"fixed inset-0 z-[9998] overflow-y-auto bg-black/90 p-4 backdrop-blur-sm\">\n      <div className=\"mx-auto max-w-3xl\">\n        <div className=\"sticky top-4 z-10 mb-4 flex items-center justify-between border border-white/15 bg-black px-4 py-3 text-white\">\n          <div>\n            <p className=\"text-xs font-black uppercase tracking-[0.16em] text-[#f6b800]\">{job.photos.length} photo{job.photos.length === 1 ? \"\" : \"s\"}</p>\n            <h3 className=\"text-lg font-black\">{job.title}</h3>\n          </div>\n          <button onClick={onClose} className=\"flex h-10 w-10 items-center justify-center border border-white/20 text-2xl font-black\">\u00d7</button>\n        </div>\n\n        <div className=\"grid gap-4\">\n          {job.photos.map((photo, index) => (\n            <figure key={photo + index} className=\"border border-white/10 bg-black\">\n              <img src={photo} alt={`${job.title} photo ${index + 1}`} className=\"h-auto w-full object-contain\" />\n              {index === 0 ? <figcaption className=\"px-4 py-3 text-xs font-black uppercase tracking-[0.16em] text-[#f6b800]\">Cover photo</figcaption> : null}\n            </figure>\n          ))}\n        </div>\n      </div>\n    </div>\n  );\n}\n\nfunction EditJobModal({ job, ownerKey, onClose, onUpdated }: { job: JobListing; ownerKey: string; onClose: () => void; onUpdated: () => void }) {\n  const [title, setTitle] = useState(job.title);\n  const [city, setCity] = useState(job.city);\n  const [group, setGroup] = useState<VehicleGroup>(job.group);\n  const [rate, setRate] = useState(job.rate);\n  const [contactNumber, setContactNumber] = useState(job.contactNumber);\n  const [description, setDescription] = useState(job.description);\n  const [saving, setSaving] = useState(false);\n\n  async function save() {\n    setSaving(true);\n\n    const { data, error } = await supabase.rpc(\"update_job_listing\", {\n      p_job_id: job.id,\n      p_owner_key: ownerKey,\n      p_title: title,\n      p_city: city,\n      p_vehicle_group: group,\n      p_rate: rate,\n      p_contact_number: contactNumber,\n      p_description: description,\n    });\n\n    setSaving(false);\n\n    if (error || data !== true) {\n      alert(\"This post can only be edited from the device that created it.\");\n      return;\n    }\n\n    onUpdated();\n  }\n\n  return (\n    <div className=\"fixed inset-0 z-[9999] overflow-y-auto bg-black/90 p-4 backdrop-blur-sm\">\n      <div className=\"mx-auto max-w-xl border border-[#f6b800] bg-black p-5 text-white\">\n        <div className=\"mb-4 flex items-center justify-between\">\n          <h3 className=\"text-2xl font-black\">Edit post</h3>\n          <button onClick={onClose} className=\"flex h-10 w-10 items-center justify-center border border-white/20 text-2xl font-black\">\u00d7</button>\n        </div>\n\n        <div className=\"grid gap-3\">\n          <input value={title} onChange={(e) => setTitle(e.target.value)} className=\"h-12 bg-white px-4 font-bold text-black\" />\n          <input value={city} onChange={(e) => setCity(e.target.value)} className=\"h-12 bg-white px-4 font-bold text-black\" />\n          <select value={group} onChange={(e) => setGroup(e.target.value as VehicleGroup)} className=\"h-12 bg-white px-4 font-bold text-black\">\n            {vehicleGroups.map((item) => <option key={item}>{item}</option>)}\n          </select>\n          <input value={rate} onChange={(e) => setRate(e.target.value)} className=\"h-12 bg-white px-4 font-bold text-black\" />\n          <input value={contactNumber} onChange={(e) => setContactNumber(e.target.value)} className=\"h-12 bg-white px-4 font-bold text-black\" />\n          <textarea value={description} onChange={(e) => setDescription(e.target.value)} className=\"min-h-32 bg-white px-4 py-3 font-bold text-black\" />\n          <button onClick={save} disabled={saving} className=\"h-12 bg-[#f6b800] font-black uppercase tracking-wide text-black\">\n            {saving ? \"Saving...\" : \"Save changes\"}\n          </button>\n        </div>\n      </div>\n    </div>\n  );\n}\n\nfunction Header({ darkMode, toggleDarkMode }: { darkMode: boolean; toggleDarkMode: () => void }) {\n  return (\n    <header className={`sticky top-0 z-50 border-b transition-colors duration-500 ${darkMode ? \"border-white/10 bg-black\" : \"border-black/10 bg-white\"}`}>\n      <div className=\"grid h-20 w-full grid-cols-[92px_1fr_52px] items-center px-4\">\n        <div className=\"flex items-center gap-2\">\n          <Link href=\"/\" className={`flex h-10 w-10 items-center justify-center text-3xl font-black ${darkMode ? \"text-white\" : \"text-black\"}`} aria-label=\"Open menu\">\u2630</Link>\n          <Link href=\"/login\" aria-label=\"Log in or sign up\" className={`flex h-10 w-10 items-center justify-center rounded-full border ${darkMode ? \"border-yellow-400/60 bg-yellow-400 text-black\" : \"border-black/10 bg-white text-black shadow-[0_8px_18px_rgba(0,0,0,0.08)]\"}`}>\n            <HeaderUserPlusIcon />\n          </Link>\n        </div>\n\n        <Link href=\"/\" className=\"flex min-w-0 items-center justify-center overflow-visible\" aria-label=\"Go to LoadLink homepage\">\n          <LoadLinkLogo />\n        </Link>\n\n        <button onClick={toggleDarkMode} aria-label={darkMode ? \"Switch to light mode\" : \"Switch to dark mode\"} className={`ml-auto flex h-10 w-10 items-center justify-center rounded-full border transition-all duration-500 ${darkMode ? \"border-yellow-400/70 bg-yellow-400 text-black\" : \"border-black/10 bg-black text-[#f6b800]\"}`}>\n          {darkMode ? <HeaderSunIcon /> : <HeaderMoonIcon />}\n        </button>\n      </div>\n    </header>\n  );\n}\n\nfunction Footer({ darkMode }: { darkMode: boolean }) {\n  const sections = [\"Company\", \"Logistics\", \"Services\", \"Customers\"];\n\n  return (\n    <footer className={`px-5 py-10 transition-colors duration-500 ${darkMode ? \"bg-black text-white\" : \"bg-white text-black\"}`}>\n      <div className=\"mx-auto max-w-5xl\">\n        <div className=\"mb-8 flex items-center justify-center overflow-visible\">\n          <LoadLinkLogo />\n        </div>\n\n        <div className=\"grid gap-0\">\n          {sections.map((section) => (\n            <details key={section} className={`border-t py-7 ${darkMode ? \"border-white/10\" : \"border-black/10\"}`}>\n              <summary className=\"flex cursor-pointer list-none items-center justify-between text-3xl font-black tracking-[-0.04em]\">\n                {section}\n                <span className=\"text-[#b88900]\">\u2304</span>\n              </summary>\n              <p className={`mt-4 text-sm leading-7 ${darkMode ? \"text-white/60\" : \"text-black/60\"}`}>More LoadLink information will be added here.</p>\n            </details>\n          ))}\n        </div>\n      </div>\n    </footer>\n  );\n}\n\nfunction HeaderUserPlusIcon() {\n  return (\n    <svg aria-hidden=\"true\" width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" className=\"shrink-0\">\n      <path d=\"M10.4 11.2a4.1 4.1 0 1 0 0-8.2 4.1 4.1 0 0 0 0 8.2ZM3.2 20.4c.55-3.85 3.35-6.4 7.2-6.4 2.1 0 3.86.76 5.1 2.07\" stroke=\"currentColor\" strokeWidth=\"2.1\" strokeLinecap=\"round\" strokeLinejoin=\"round\" />\n      <path d=\"M18 14.2v6.6M14.7 17.5h6.6\" stroke=\"currentColor\" strokeWidth=\"2.4\" strokeLinecap=\"round\" />\n    </svg>\n  );\n}\n\nfunction HeaderSunIcon() {\n  return (\n    <svg aria-hidden=\"true\" width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" className=\"shrink-0\">\n      <circle cx=\"12\" cy=\"12\" r=\"4.5\" fill=\"currentColor\" />\n      <path d=\"M12 2.5v2.2M12 19.3v2.2M21.5 12h-2.2M4.7 12H2.5M18.72 5.28l-1.56 1.56M6.84 17.16l-1.56 1.56M18.72 18.72l-1.56-1.56M6.84 6.84 5.28 5.28\" stroke=\"currentColor\" strokeWidth=\"1.8\" strokeLinecap=\"round\" />\n    </svg>\n  );\n}\n\nfunction HeaderMoonIcon() {\n  return (\n    <svg aria-hidden=\"true\" width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" className=\"shrink-0\">\n      <path d=\"M20.2 14.1A8.7 8.7 0 0 1 9.9 3.8a8.7 8.7 0 1 0 10.3 10.3Z\" fill=\"currentColor\" />\n    </svg>\n  );\n}\n";
const LIST_PAGE_CODE = "\"use client\";\n\nimport Link from \"next/link\";\nimport { ChangeEvent, FormEvent, useState } from \"react\";\nimport { useRouter } from \"next/navigation\";\nimport LoadLinkLogo from \"@/components/LoadLinkLogo\";\nimport LoadLinkLoading from \"@/components/LoadLinkLoading\";\nimport { isSupabaseConfigured, supabase } from \"@/lib/supabaseClient\";\n\ntype VehicleGroup = \"Catering / Event\" | \"Trucks / Trailers\" | \"Farming / Mining\";\n\nconst cityOptions = [\"Johannesburg\", \"Sandton\", \"Midrand\", \"Pretoria\", \"Centurion\", \"Soweto\", \"Tembisa\", \"Kempton Park\", \"Boksburg\", \"Benoni\", \"Germiston\", \"Randburg\", \"Roodepoort\", \"Durban\", \"Pinetown\", \"Umhlanga\", \"Cape Town\", \"Bellville\", \"Stellenbosch\", \"Paarl\", \"George\", \"Gqeberha\", \"East London\", \"Bloemfontein\", \"Kimberley\", \"Rustenburg\", \"Polokwane\", \"Mbombela\", \"Emalahleni\", \"Mthatha\"];\nconst groups: VehicleGroup[] = [\"Catering / Event\", \"Trucks / Trailers\", \"Farming / Mining\"];\n\nfunction wait(ms: number) {\n  return new Promise((resolve) => setTimeout(resolve, ms));\n}\n\nfunction normalizePhone(value: string) {\n  return value.replace(/[^\\d+]/g, \"\");\n}\n\nfunction isValidSouthAfricanPhone(value: string) {\n  const clean = normalizePhone(value);\n  return /^0\\d{9}$/.test(clean) || /^\\+27\\d{9}$/.test(clean);\n}\n\nfunction getOwnerKey() {\n  const existing = localStorage.getItem(\"loadlink-device-key\");\n  if (existing) return existing;\n\n  const key = `${Date.now()}-${Math.random().toString(36).slice(2)}-${crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2)}`;\n  localStorage.setItem(\"loadlink-device-key\", key);\n  return key;\n}\n\nfunction saveOwnedJob(jobId: string, ownerKey: string) {\n  try {\n    const saved = JSON.parse(localStorage.getItem(\"loadlink-owned-job-keys\") || \"{}\");\n    saved[jobId] = ownerKey;\n    localStorage.setItem(\"loadlink-owned-job-keys\", JSON.stringify(saved));\n  } catch {\n    localStorage.setItem(\"loadlink-owned-job-keys\", JSON.stringify({ [jobId]: ownerKey }));\n  }\n}\n\nfunction resizePhoto(file: File): Promise<Blob> {\n  return new Promise((resolve, reject) => {\n    const reader = new FileReader();\n\n    reader.onload = () => {\n      const image = new Image();\n\n      image.onload = () => {\n        const maxWidth = 1000;\n        const scale = Math.min(1, maxWidth / image.width);\n        const canvas = document.createElement(\"canvas\");\n\n        canvas.width = Math.round(image.width * scale);\n        canvas.height = Math.round(image.height * scale);\n\n        const ctx = canvas.getContext(\"2d\");\n        if (!ctx) {\n          reject(new Error(\"Could not process image.\"));\n          return;\n        }\n\n        ctx.drawImage(image, 0, 0, canvas.width, canvas.height);\n        canvas.toBlob((blob) => {\n          if (!blob) reject(new Error(\"Could not convert image.\"));\n          else resolve(blob);\n        }, \"image/jpeg\", 0.74);\n      };\n\n      image.onerror = () => reject(new Error(\"Could not read image.\"));\n      image.src = String(reader.result);\n    };\n\n    reader.onerror = () => reject(new Error(\"Could not read file.\"));\n    reader.readAsDataURL(file);\n  });\n}\n\nexport default function ListJobPage() {\n  const router = useRouter();\n\n  const [title, setTitle] = useState(\"\");\n  const [city, setCity] = useState(\"Johannesburg\");\n  const [group, setGroup] = useState<VehicleGroup>(\"Trucks / Trailers\");\n  const [rate, setRate] = useState(\"\");\n  const [postedBy, setPostedBy] = useState(\"\");\n  const [contactNumber, setContactNumber] = useState(\"\");\n  const [description, setDescription] = useState(\"\");\n  const [packageType, setPackageType] = useState<\"standard\" | \"pro\">(\"standard\");\n  const [files, setFiles] = useState<File[]>([]);\n  const [previewPhotos, setPreviewPhotos] = useState<string[]>([]);\n  const [isSaving, setIsSaving] = useState(false);\n  const [message, setMessage] = useState(\"\");\n\n  const photoLimit = packageType === \"pro\" ? 15 : 5;\n\n  async function handlePhotos(e: ChangeEvent<HTMLInputElement>) {\n    const selectedFiles = Array.from(e.target.files || []);\n    setMessage(\"\");\n\n    if (selectedFiles.length < 1) {\n      setFiles([]);\n      setPreviewPhotos([]);\n      return;\n    }\n\n    if (selectedFiles.length > photoLimit) {\n      setMessage(`This package allows up to ${photoLimit} photos. Extra photos were ignored.`);\n    }\n\n    const limitedFiles = selectedFiles.slice(0, photoLimit);\n    setFiles(limitedFiles);\n\n    const previews = await Promise.all(limitedFiles.map((file) => new Promise<string>((resolve, reject) => {\n      const reader = new FileReader();\n      reader.onload = () => resolve(String(reader.result));\n      reader.onerror = reject;\n      reader.readAsDataURL(file);\n    })));\n\n    setPreviewPhotos(previews);\n  }\n\n  async function uploadPhotos() {\n    const uploadedUrls: string[] = [];\n\n    for (let index = 0; index < files.length; index += 1) {\n      const file = files[index];\n      const resizedBlob = await resizePhoto(file);\n      const safeFileName = file.name.replace(/[^a-z0-9.]/gi, \"-\").toLowerCase();\n      const filePath = `jobs/${Date.now()}-${index}-${safeFileName}`;\n\n      const { error } = await supabase.storage.from(\"job-photos\").upload(filePath, resizedBlob, {\n        cacheControl: \"3600\",\n        contentType: \"image/jpeg\",\n        upsert: false,\n      });\n\n      if (error) throw error;\n\n      const { data } = supabase.storage.from(\"job-photos\").getPublicUrl(filePath);\n      uploadedUrls.push(data.publicUrl);\n    }\n\n    return uploadedUrls;\n  }\n\n  async function submitJob(e: FormEvent<HTMLFormElement>) {\n    e.preventDefault();\n    setMessage(\"\");\n\n    if (!isSupabaseConfigured) {\n      setMessage(\"Supabase is not connected. Add the Supabase URL and anon key in Vercel, then redeploy.\");\n      return;\n    }\n\n    if (!isValidSouthAfricanPhone(contactNumber)) {\n      setMessage(\"Enter a valid South African number, for example 0821234567 or +27821234567.\");\n      return;\n    }\n\n    if (files.length < 1) {\n      setMessage(\"Please upload at least 1 photo.\");\n      return;\n    }\n\n    setIsSaving(true);\n    const minimumLoading = wait(900);\n\n    try {\n      const ownerKey = getOwnerKey();\n      const uploadedUrls = await uploadPhotos();\n\n      const { data, error } = await supabase\n        .from(\"job_listings\")\n        .insert({\n          title,\n          city,\n          vehicle_group: group,\n          rate,\n          posted_by: postedBy,\n          contact_number: contactNumber,\n          description,\n          photos: uploadedUrls,\n          sponsored: false,\n          package_type: packageType,\n          owner_key: ownerKey,\n        })\n        .select(\"id\")\n        .single();\n\n      if (error) throw error;\n\n      if (data?.id) saveOwnedJob(data.id, ownerKey);\n\n      await minimumLoading;\n      router.push(\"/jobs?posted=success\");\n    } catch (error) {\n      await minimumLoading;\n      setIsSaving(false);\n      setMessage(error instanceof Error ? error.message : \"The listing could not be uploaded.\");\n    }\n  }\n\n  return (\n    <main className=\"min-h-screen bg-black text-white transition-colors duration-500\">\n      {isSaving ? <LoadLinkLoading /> : null}\n\n      <header className=\"sticky top-0 z-50 border-b border-white/10 bg-black\">\n        <div className=\"grid h-20 grid-cols-[80px_1fr_80px] items-center px-4\">\n          <Link href=\"/jobs\" className=\"text-sm font-black text-[#f6b800]\">Back</Link>\n          <Link href=\"/\" className=\"flex justify-center overflow-visible\">\n            <LoadLinkLogo />\n          </Link>\n          <div />\n        </div>\n      </header>\n\n      <section className=\"mx-auto max-w-3xl px-5 py-8\">\n        <p className=\"text-xs font-black uppercase tracking-[0.26em] text-[#f6b800]\">Shared listing</p>\n        <h1 className=\"mt-3 text-5xl font-black tracking-[-0.06em]\">List a job</h1>\n        <p className=\"mt-4 text-sm leading-7 text-white/65\">\n          This post will be locked to this device. Only the browser that created it can edit or delete it.\n        </p>\n\n        <form onSubmit={submitJob} className=\"mt-7 grid gap-4 border border-[#f6b800] bg-[#080808] p-5\">\n          <input required value={title} onChange={(e) => setTitle(e.target.value)} placeholder=\"Job title\" className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\" />\n\n          <select value={city} onChange={(e) => setCity(e.target.value)} className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\">\n            {cityOptions.map((item) => <option key={item} value={item}>{item}</option>)}\n          </select>\n\n          <select value={group} onChange={(e) => setGroup(e.target.value as VehicleGroup)} className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\">\n            {groups.map((item) => <option key={item} value={item}>{item}</option>)}\n          </select>\n\n          <input required value={rate} onChange={(e) => setRate(e.target.value)} placeholder=\"Rate / budget, e.g. R2 500 per load\" className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\" />\n          <input required value={postedBy} onChange={(e) => setPostedBy(e.target.value)} placeholder=\"Posted by / company name\" className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\" />\n\n          <input required type=\"tel\" value={contactNumber} onChange={(e) => setContactNumber(e.target.value)} placeholder=\"Contact number, e.g. 0821234567\" className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\" />\n\n          <textarea required value={description} onChange={(e) => setDescription(e.target.value)} placeholder=\"Describe the job\" className=\"min-h-32 border border-white/15 bg-white px-4 py-3 font-bold text-black outline-none\" />\n\n          <select value={packageType} onChange={(e) => setPackageType(e.target.value as \"standard\" | \"pro\")} className=\"h-12 border border-white/15 bg-white px-4 font-bold text-black outline-none\">\n            <option value=\"standard\">Standard: 1\u20135 photos</option>\n            <option value=\"pro\">Pro: up to 15 photos</option>\n          </select>\n\n          <div className=\"border border-[#f6b800]/50 bg-[#120f03] p-4\">\n            <p className=\"text-xs font-black uppercase tracking-[0.2em] text-[#f6b800]\">Cover photo matters</p>\n            <p className=\"mt-2 text-sm font-bold leading-6 text-white/75\">\n              Upload your strongest photo first. It becomes the cover image buyers see before opening the full gallery.\n            </p>\n          </div>\n\n          <label className=\"border border-white/15 bg-black p-4\">\n            <span className=\"block text-xs font-black uppercase tracking-[0.2em] text-[#f6b800]\">Upload photos</span>\n            <input type=\"file\" accept=\"image/*\" multiple onChange={handlePhotos} className=\"mt-3 block w-full text-sm\" />\n            <span className=\"mt-3 block text-xs text-white/55\">Selected: {files.length}/{photoLimit} photos</span>\n          </label>\n\n          {previewPhotos.length > 0 ? (\n            <div className=\"grid grid-cols-3 gap-2\">\n              {previewPhotos.slice(0, 6).map((photo, index) => (\n                <div key={photo + index} className=\"relative aspect-square overflow-hidden bg-white/5\">\n                  <img src={photo} alt=\"\" className=\"h-full w-full object-cover\" />\n                  {index === 0 ? <span className=\"absolute left-1 top-1 bg-[#f6b800] px-2 py-1 text-[10px] font-black uppercase text-black\">Cover</span> : null}\n                </div>\n              ))}\n            </div>\n          ) : null}\n\n          {message ? <p className=\"border border-[#f6b800] bg-black p-3 text-sm font-bold text-[#f6b800]\">{message}</p> : null}\n\n          <button type=\"submit\" className=\"h-12 border border-[#f6b800] bg-[#f6b800] text-sm font-black uppercase tracking-wide text-black\">Publish shared listing</button>\n        </form>\n      </section>\n    </main>\n  );\n}\n";
const SQL_CODE = "-- LoadLink owner controls + post view notifications.\n-- Run this once in Supabase SQL Editor.\n\nalter table public.job_listings\nadd column if not exists owner_key text not null default '';\n\nalter table public.job_listings\nadd column if not exists view_count integer not null default 0;\n\nalter table public.job_listings\nadd column if not exists last_viewed_at timestamptz;\n\ncreate or replace function public.delete_job_listing(\n  p_job_id uuid,\n  p_owner_key text\n)\nreturns boolean\nlanguage plpgsql\nsecurity definer\nset search_path = public\nas $$\ndeclare\n  affected_count integer;\nbegin\n  delete from public.job_listings\n  where id = p_job_id\n    and owner_key = p_owner_key\n    and length(owner_key) > 20;\n\n  get diagnostics affected_count = row_count;\n  return affected_count > 0;\nend;\n$$;\n\ncreate or replace function public.update_job_listing(\n  p_job_id uuid,\n  p_owner_key text,\n  p_title text,\n  p_city text,\n  p_vehicle_group text,\n  p_rate text,\n  p_contact_number text,\n  p_description text\n)\nreturns boolean\nlanguage plpgsql\nsecurity definer\nset search_path = public\nas $$\ndeclare\n  affected_count integer;\nbegin\n  update public.job_listings\n  set\n    title = p_title,\n    city = p_city,\n    vehicle_group = p_vehicle_group,\n    rate = p_rate,\n    contact_number = p_contact_number,\n    description = p_description\n  where id = p_job_id\n    and owner_key = p_owner_key\n    and length(owner_key) > 20;\n\n  get diagnostics affected_count = row_count;\n  return affected_count > 0;\nend;\n$$;\n\ncreate or replace function public.increment_job_view(\n  p_job_id uuid,\n  p_viewer_key text\n)\nreturns boolean\nlanguage plpgsql\nsecurity definer\nset search_path = public\nas $$\ndeclare\n  affected_count integer;\nbegin\n  update public.job_listings\n  set\n    view_count = coalesce(view_count, 0) + 1,\n    last_viewed_at = now()\n  where id = p_job_id\n    and (owner_key is null or owner_key = '' or owner_key <> p_viewer_key);\n\n  get diagnostics affected_count = row_count;\n  return affected_count > 0;\nend;\n$$;\n\ngrant execute on function public.delete_job_listing(uuid, text) to anon, authenticated;\ngrant execute on function public.update_job_listing(uuid, text, text, text, text, text, text, text) to anon, authenticated;\ngrant execute on function public.increment_job_view(uuid, text) to anon, authenticated;\n";

function write(filePath, content) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content);
}

function appendGlobals() {
  const globalsPath = path.join(root, "app", "globals.css");
  if (!fs.existsSync(globalsPath)) {
    write(globalsPath, "");
  }

  let css = fs.readFileSync(globalsPath, "utf8");

  // Remove older logo filter patches that caused blocky glow/black rectangles.
  css = css.replace(/\/\* LoadLink dark mode logo fix:[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LOADLINK DARK LOGO FINAL FIX[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LoadLink dark mode business text safety fix[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LoadLink logo swap uses real light\/dark logo files[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LOADLINK EMBEDDED FINAL LOGO SAFETY[\s\S]*?\}\n?/g, "");

  const finalCss = `
/* LOADLINK SMOOTH OWNER FIX */
html,
body,
main,
header,
section,
article,
footer,
button,
a,
input,
textarea,
select {
  transition-property: background-color, color, border-color, box-shadow, opacity, transform;
  transition-duration: 360ms;
  transition-timing-function: cubic-bezier(.22, .61, .36, 1);
}

.loadlink-logo-wrap {
  position: relative;
  isolation: isolate;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: clamp(134px, 32vw, 172px);
  max-width: 100%;
  overflow: visible;
}

.loadlink-logo-img {
  position: relative;
  z-index: 2;
  width: 100% !important;
  height: auto !important;
  object-fit: contain !important;
  filter: none !important;
  display: block;
}

.loadlink-logo-glow {
  position: absolute;
  z-index: 0;
  left: 50%;
  top: 50%;
  width: 116%;
  height: 104%;
  transform: translate(-50%, -50%);
  border-radius: 999px;
  pointer-events: none;
  opacity: .7;
  filter: blur(20px);
  background:
    radial-gradient(circle at 50% 50%,
      rgba(246, 184, 0, .32) 0%,
      rgba(246, 184, 0, .19) 35%,
      rgba(246, 184, 0, .08) 56%,
      rgba(246, 184, 0, 0) 78%);
}

img.loadlink-logo-img,
main.bg-black img.loadlink-logo-img,
header img.loadlink-logo-img,
.bg-black img.loadlink-logo-img {
  filter: none !important;
}

@media (min-width: 768px) {
  .loadlink-logo-wrap {
    width: clamp(150px, 18vw, 188px);
  }
}

@media (prefers-reduced-motion: reduce) {
  html,
  body,
  main,
  header,
  section,
  article,
  footer,
  button,
  a,
  input,
  textarea,
  select {
    transition-duration: 0ms !important;
  }
}
`;

  if (!css.includes("LOADLINK SMOOTH OWNER FIX")) {
    css += finalCss;
  }

  fs.writeFileSync(globalsPath, css);
}

write(path.join(root, "public", "images", "loadlink-logo-light.png"), Buffer.from(LIGHT_LOGO_BASE64, "base64"));
write(path.join(root, "public", "images", "loadlink-logo-dark.png"), Buffer.from(DARK_LOGO_BASE64, "base64"));
write(path.join(root, "public", "images", "loadlink-logo.png"), Buffer.from(LIGHT_LOGO_BASE64, "base64"));
write(path.join(root, "components", "LoadLinkLogo.tsx"), COMPONENT_CODE);
write(path.join(root, "app", "jobs", "page.tsx"), JOBS_PAGE_CODE);
write(path.join(root, "app", "jobs", "list", "page.tsx"), LIST_PAGE_CODE);
write(path.join(root, "supabase-owner-controls.sql"), SQL_CODE);
appendGlobals();

write(path.join(root, "loadlink-smooth-owner-fix-installed.txt"), `Installed at ${new Date().toISOString()}\n`);

console.log("LOADLINK SMOOTH OWNER FIX INSTALLED");
console.log("Updated:");
console.log("- logo size reduced slightly");
console.log("- gold glow blended instead of blocky");
console.log("- smoother light/dark transitions");
console.log("- owner edit/delete using device owner key");
console.log("- post view count/notification");
console.log("- greeting message options");
